module top_module(
  input [7:0] A,
  input [7:0] B,
  output reg [7:0] sum,
  output reg carry
);reg [8:0] overflow_result;

  always @ (A or B) begin
    overflow_result = A + B;
    if (overflow_result > 255) begin
      carry = 1;
      sum = overflow_result[7:0];
    end else begin
      carry = 0;
      sum = overflow_result[7:0];
    end
  end

endmodule
